Send Message.code:
// Send a prompt to Claude.
// The model's reply is written to state.data.
prompt(
  // 1) The message text. Reference upstream state with $.
  `Summarize this text: ${JSON.stringify($.data)}`,
  {
    // 2) Model id. Defaults to the latest Sonnet if omitted.
    model: 'claude-sonnet-4-6',
    // 3) Maximum tokens to generate in the reply.
    max_tokens: 1024,
    // 4) 0.0 = analytical / deterministic, 1.0 = creative.
    temperature: 0.7,
  }
);
